#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <string.h>
#include <string>
#include <sys/time.h>
#include <cuda_runtime.h>

#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

static int do_verify = 0;

static struct option long_options[] = {
    {"input", 1, NULL, 'i'},
    {"size", 1, NULL, 's'},
    {"verify", 0, NULL, 'v'},
    {"platform", 1, NULL, 'p'},
    {"device", 1, NULL, 'd'},
    {0, 0, 0, 0}
};

__global__ void lud_diagonal(float *m, int matrix_dim, int offset);
__global__ void lud_perimeter(float *m, int matrix_dim, int offset);
__global__ void lud_internal(float *m, int matrix_dim, int offset);

int main(int argc, char *argv[])
{
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    size_t matrix_dim = 32;
    int opt, option_index = 0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m, *mm;
    stopwatch sw;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:", long_options, &option_index)) != -1) {
        switch (opt) {
        case 'i':
            input_file = optarg;
            break;
        case 'v':
            do_verify = 1;
            break;
        case 's':
            matrix_dim = atoi(optarg);
            printf("Generate input matrix internally, size =%lu\n", matrix_dim);
            break;
        case 'p':
            // platform_id_inuse ignored in CUDA
            break;
        case 'd':
            // device_id_inuse ignored in CUDA
            break;
        case '?':
            fprintf(stderr, "invalid option\n");
            break;
        case ':':
            fprintf(stderr, "missing argument\n");
            break;
        default:
            fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
            exit(EXIT_FAILURE);
        }
    }

    if ((optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    }
    else if (matrix_dim) {
        printf("Creating matrix internally size=%lu\n", matrix_dim);
        ret = create_matrix(&m, matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix internally size=%lu\n", matrix_dim);
            exit(EXIT_FAILURE);
        }
    }
    else {
        printf("No input file specified!\n");
        exit(EXIT_FAILURE);
    }

    if (do_verify) {
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

    float *d_m = NULL;
    cudaError_t err = cudaMalloc((void **)&d_m, matrix_dim * matrix_dim * sizeof(float));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }

    err = cudaMemcpy(d_m, m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy H2D failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }

    stopwatch_start(&sw);

    size_t i = 0;
    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        // Launch lud_diagonal kernel
        dim3 dimBlockDiag(BLOCK_SIZE, 1, 1);
        dim3 dimGridDiag(1, 1, 1);
        lud_diagonal<<<dimGridDiag, dimBlockDiag>>>(d_m, matrix_dim, i);
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "lud_diagonal kernel launch failed: %s\n", cudaGetErrorString(err));
            cudaFree(d_m);
            exit(EXIT_FAILURE);
        }
        cudaDeviceSynchronize();

        // Launch lud_perimeter kernel
        int num_blocks_peri = (int)((matrix_dim - i) / BLOCK_SIZE - 1);
        if (num_blocks_peri > 0) {
            dim3 dimBlockPeri(BLOCK_SIZE * 2, 1, 1);
            dim3 dimGridPeri(num_blocks_peri, 1, 1);
            lud_perimeter<<<dimGridPeri, dimBlockPeri>>>(d_m, matrix_dim, i);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                fprintf(stderr, "lud_perimeter kernel launch failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_m);
                exit(EXIT_FAILURE);
            }
            cudaDeviceSynchronize();
        }

        // Launch lud_internal kernel
        if (num_blocks_peri > 0) {
            dim3 dimBlockInternal(BLOCK_SIZE, BLOCK_SIZE, 1);
            dim3 dimGridInternal(num_blocks_peri, num_blocks_peri, 1);
            lud_internal<<<dimGridInternal, dimBlockInternal>>>(d_m, matrix_dim, i);
            err = cudaGetLastError();
            if (err != cudaSuccess) {
                fprintf(stderr, "lud_internal kernel launch failed: %s\n", cudaGetErrorString(err));
                cudaFree(d_m);
                exit(EXIT_FAILURE);
            }
            cudaDeviceSynchronize();
        }
    }

    // Last diagonal block
    dim3 dimBlockDiag(BLOCK_SIZE, 1, 1);
    dim3 dimGridDiag(1, 1, 1);
    lud_diagonal<<<dimGridDiag, dimBlockDiag>>>(d_m, matrix_dim, i);
    err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "lud_diagonal kernel launch failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }
    cudaDeviceSynchronize();

    err = cudaMemcpy(m, d_m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy D2H failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_m);
        exit(EXIT_FAILURE);
    }

    stopwatch_stop(&sw);

    if (do_verify) {
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim);
        free(mm);
    }

    free(m);
    cudaFree(d_m);

    return 0;
}

